const b = ($input.first().json.body) || {};
let ts = b.timestamp;
if (ts == null || ts === '') ts = Math.floor(Date.now()/1000);
else { ts = Number(ts); if (ts > 1e12) ts = Math.floor(ts/1000); }
const phone = String(b.phone||'').replace(/[^\d]/g,'');
return [{ json: { phone, name: b.name||null, text: b.text||'', wamid: b.wamid||null, ts, type: b.type||'text', direction: 'out', status: b.status||'sent' } }];
